// Build a model row. All optional fields default to null so callers can
// trust the shape; mission defaults to an empty array.
const m = (row) => ({
  variant: null, type_designator: null, mission: [],
  year_first: null, year_last: null,
  mtow_kg: null, seats: null, engine_type: null, engine_count: 1,
  cruise_kts: null, range_nm: null, fuel_burn_lph: null, ceiling_ft: null,
  wikipedia_url: null, hero_image_url: null, description: null,
  source: 'seed', aliases: [],
  ...row,
  full_name: row.full_name ?? `${makeName(row.make)} ${row.family}${row.variant ? ' ' + row.variant : ''}`,
  slug: row.slug ?? `${row.make}-${(row.family + (row.variant ? '-' + row.variant : '')).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '')}`,
});

function makeName(slug) {
  const found = MAKES_SEED.find((mk) => mk.slug === slug);
  return found ? found.name : slug;
}

